@Test
public void testParseOctalMultipleTrailingSpacesAndNuls() throws Exception {
    byte[] buffer = new byte[] {'1', '2', '3', ' ', ' ', 0, 0};
    long result = TarUtils.parseOctal(buffer, 0, 7);
    assertEquals(83L, result);
}

@Test
public void testParseOctalThreeTrailingSpaces() throws Exception {
    byte[] buffer = new byte[] {'7', '7', ' ', ' ', ' '};
    long result = TarUtils.parseOctal(buffer, 0, 5);
    assertEquals(63L, result);
}

@Test
public void testParseOctalAlternatingTrailingNulsAndSpaces() throws Exception {
    byte[] buffer = new byte[] {'5', '4', '3', 0, ' ', 0};
    long result = TarUtils.parseOctal(buffer, 0, 6);
    assertEquals(355L, result);
}
